const body = $input.first().json;
const script = (body.script || '').trim();
const scriptType = body.script_type || 'server';
const aiReview = body.ai_review !== false;

if (!script || script.length < 10) {
  return [{ json: { valid: false, error: 'Script too short' } }];
}

// Static lint rules (instant, no AI needed)
const issues = [];

if (/new GlideRecord/.test(script) && /while.*\.next\(\)/.test(script) && !/setLimit/.test(script)) {
  issues.push({ id: 'no-limit', category: 'Performance', severity: 'warning', message: 'Missing setLimit() — can timeout on large tables', fix: 'Add gr.setLimit(100) before gr.query()' });
}
if (/\.getRowCount\(\)/.test(script)) {
  issues.push({ id: 'getrowcount', category: 'Performance', severity: 'warning', message: 'getRowCount() loads all records — use GlideAggregate', fix: 'Replace with GlideAggregate and addAggregate("COUNT")' });
}
if (/while.*\.next\(\)[\s\S]*?\.update\(\)/m.test(script)) {
  issues.push({ id: 'update-in-loop', category: 'Performance', severity: 'error', message: 'update() inside while loop — very slow on large datasets', fix: 'Use GlideRecord.updateMultiple() for bulk updates' });
}
if (/new GlideRecord/.test(script) && /while.*\.next\(\)/.test(script) && !/\.query\(\)/.test(script)) {
  issues.push({ id: 'no-query', category: 'Bug', severity: 'error', message: 'GlideRecord without gr.query() before while loop', fix: 'Add gr.query() before while (gr.next())' });
}
if (/['"\`][0-9a-f]{32}['"\`]/.test(script)) {
  issues.push({ id: 'hardcoded-sysid', category: 'Security', severity: 'warning', message: 'Hardcoded sys_id detected — use system property instead', fix: 'Use gs.getProperty("my.sysid") to store the sys_id' });
}
if (/\beval\s*\(/.test(script)) {
  issues.push({ id: 'eval', category: 'Security', severity: 'error', message: 'eval() is a security vulnerability', fix: 'Refactor to avoid eval(). Use JSON.parse() or direct calls' });
}
if (scriptType === 'client_script' && /new GlideRecord/.test(script)) {
  issues.push({ id: 'gr-in-client', category: 'Bug', severity: 'error', message: 'GlideRecord cannot be used in Client Scripts', fix: 'Use GlideAjax to call a Script Include instead' });
}
if (/RESTMessageV2|GlideHTTPClient/.test(script) && !/try\s*\{/.test(script)) {
  issues.push({ id: 'no-try-catch', category: 'BestPractice', severity: 'warning', message: 'REST call without try/catch — network failures will break the script', fix: 'Wrap REST calls in try/catch block' });
}
if (/\bgs\.log\s*\(/.test(script)) {
  issues.push({ id: 'gs-log', category: 'BestPractice', severity: 'info', message: 'gs.log() is deprecated', fix: 'Use gs.info(), gs.warn(), or gs.error() instead' });
}
if (script.length > 200 && !/\/\/|\/\*/.test(script)) {
  issues.push({ id: 'no-comments', category: 'Quality', severity: 'info', message: 'No comments found in script', fix: 'Add JSDoc or inline comments for maintainability' });
}

const errors = issues.filter(i => i.severity === 'error').length;
const warnings = issues.filter(i => i.severity === 'warning').length;
const info = issues.filter(i => i.severity === 'info').length;
const score = Math.max(0, 100 - (errors * 25) - (warnings * 10) - (info * 3));
const grade = score >= 90 ? 'A' : score >= 75 ? 'B' : score >= 60 ? 'C' : score >= 40 ? 'D' : 'F';

return [{ json: {
  valid: true,
  script: script.substring(0, 3000),
  scriptType,
  aiReview,
  static_result: { issues, score, grade, summary: { errors, warnings, info } }
} }];

const res = $input.first().json;
const lintData = $('Static Lint (Instant)').first().json;
const content = res?.choices?.[0]?.message?.content || '';
let aiReview = null;
try {
  const clean = content.replace(/```json|```/g,'').trim();
  aiReview = JSON.parse(clean.match(/\{[\s\S]*\}/)?.[0] || clean);
} catch {
  aiReview = { summary: content, critical_issues: [], suggestions: [] };
}
return [{ json: { success: true, ...lintData.static_result, ai_review: aiReview, model: res.model } }];
